const OAUTH_CONFIG = {
  clientId: 'your-client-id-here',
  clientSecret: 'your-client-secret-here', // INSECURE: See warning above
  authorizationEndpoint: 'https://your-oauth-server.com/authorize',
  tokenEndpoint: 'https://your-oauth-server.com/token',
  revocationEndpoint: 'https://your-oauth-server.com/revoke',
  userInfoEndpoint: 'https://your-oauth-server.com/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'callback',
  }),
};

const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  ID_TOKEN: '@oauth_id_token',
};

// Token refresh buffer - refresh 5 minutes before expiry
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

class OAuthTokenManager {
  constructor() {
    this.refreshTimer = null;
    this.isRefreshing = false;
    this.refreshPromise = null;
    this.onTokensUpdated = null;
    this.onAuthError = null;
  }

  setCallbacks(onTokensUpdated, onAuthError) {
    this.onTokensUpdated = onTokensUpdated;
    this.onAuthError = onAuthError;
  }

  async storeTokens(tokenResponse) {
    const expiryTime = Date.now() + (tokenResponse.expires_in || 3600) * 1000;

    const storageOperations = [
      AsyncStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, tokenResponse.access_token),
      AsyncStorage.setItem(STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()),
    ];

    if (tokenResponse.refresh_token) {
      storageOperations.push(
        AsyncStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokenResponse.refresh_token)
      );
    }

    if (tokenResponse.id_token) {
      storageOperations.push(
        AsyncStorage.setItem(STORAGE_KEYS.ID_TOKEN, tokenResponse.id_token)
      );
    }

    await Promise.all(storageOperations);

    this.scheduleTokenRefresh(tokenResponse.expires_in || 3600);

    return {
      accessToken: tokenResponse.access_token,
      refreshToken: tokenResponse.refresh_token,
      idToken: tokenResponse.id_token,
      expiryTime,
    };
  }

  async getStoredTokens() {
    const [accessToken, refreshToken, tokenExpiry, idToken] = await Promise.all([
      AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN),
      AsyncStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN),
      AsyncStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRY),
      AsyncStorage.getItem(STORAGE_KEYS.ID_TOKEN),
    ]);

    if (!accessToken) return null;

    return {
      accessToken,
      refreshToken,
      idToken,
      expiryTime: tokenExpiry ? parseInt(tokenExpiry, 10) : 0,
    };
  }

  async clearTokens() {
    this.cancelScheduledRefresh();
    await Promise.all([
      AsyncStorage.removeItem(STORAGE_KEYS.ACCESS_TOKEN),
      AsyncStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN),
      AsyncStorage.removeItem(STORAGE_KEYS.TOKEN_EXPIRY),
      AsyncStorage.removeItem(STORAGE_KEYS.ID_TOKEN),
    ]);
  }

  isTokenExpired(expiryTime) {
    return Date.now() >= expiryTime - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  scheduleTokenRefresh(expiresInSeconds) {
    this.cancelScheduledRefresh();

    const refreshTime = (expiresInSeconds - TOKEN_REFRESH_BUFFER_SECONDS) * 1000;
    if (refreshTime <= 0) {
      this.performTokenRefresh();
      return;
    }

    this.refreshTimer = setTimeout(() => {
      this.performTokenRefresh();
    }, refreshTime);
  }

  cancelScheduledRefresh() {
    if (this.refreshTimer) {
      clearTimeout(this.refreshTimer);
      this.refreshTimer = null;
    }
  }

  async performTokenRefresh() {
    if (this.isRefreshing) {
      return this.refreshPromise;
    }

    this.isRefreshing = true;
    this.refreshPromise = this._doRefresh();

    try {
      const result = await this.refreshPromise;
      return result;
    } finally {
      this.isRefreshing = false;
      this.refreshPromise = null;
    }
  }

  async _doRefresh() {
    try {
      const refreshToken = await AsyncStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);

      if (!refreshToken) {
        throw new Error('No refresh token available');
      }

      const tokenRequestBody = new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: refreshToken,
        client_id: OAUTH_CONFIG.clientId,
        client_secret: OAUTH_CONFIG.clientSecret,
      }).toString();

      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: tokenRequestBody,
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(
          `Token refresh failed: ${errorData.error || response.statusText}`
        );
      }

      const tokenData = await response.json();
      const tokens = await this.storeTokens(tokenData);

      if (this.onTokensUpdated) {
        this.onTokensUpdated(tokens);
      }

      return tokens;
    } catch (error) {
      console.error('Token refresh error:', error);

      if (this.onAuthError) {
        this.onAuthError(error);
      }

      throw error;
    }
  }

  async exchangeCodeForTokens(authorizationCode, codeVerifier) {
    const tokenRequestBody = new URLSearchParams({
      grant_type: 'authorization_code',
      code: authorizationCode,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
      ...(codeVerifier && { code_verifier: codeVerifier }),
    }).toString();

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: tokenRequestBody,
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(
        `Token exchange failed: ${errorData.error_description || errorData.error || response.statusText}`
      );
    }

    const tokenData = await response.json();
    return this.storeTokens(tokenData);
  }

  async revokeToken() {
    try {
      const accessToken = await AsyncStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
      const refreshToken = await AsyncStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);

      const revocationPromises = [];

      if (accessToken && OAUTH_CONFIG.revocationEndpoint) {
        revocationPromises.push(
          fetch(OAUTH_CONFIG.revocationEndpoint, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
              token: accessToken,
              token_type_hint: 'access_token',
              client_id: OAUTH_CONFIG.clientId,
              client_secret: OAUTH_CONFIG.clientSecret,
            }).toString(),
          })
        );
      }

      if (refreshToken && OAUTH_CONFIG.revocationEndpoint) {
        revocationPromises.push(
          fetch(OAUTH_CONFIG.revocationEndpoint, {
            method: 'POST',
            headers: {
              'Content-Type': 'application/x-www-form-urlencoded',
            },
            body: new URLSearchParams({
              token: refreshToken,
              token_type_hint: 'refresh_token',
              client_id: OAUTH_CONFIG.clientId,
              client_secret: OAUTH_CONFIG.clientSecret,
            }).toString(),
          })
        );
      }

      await Promise.allSettled(revocationPromises);
    } catch (error) {
      console.error('Token revocation error:', error);
    } finally {
      await this.clearTokens();
    }
  }

  async getValidAccessToken() {
    const tokens = await this.getStoredTokens();

    if (!tokens) {
      throw new Error('Not authenticated');
    }

    if (this.isTokenExpired(tokens.expiryTime)) {
      const refreshedTokens = await this.performTokenRefresh();
      return refreshedTokens.accessToken;
    }

    return tokens.accessToken;
  }
}

const tokenManager = new OAuthTokenManager();

// Authenticated fetch helper
async function authenticatedFetch(url, options = {}) {
  const accessToken = await tokenManager.getValidAccessToken();

  const response = await fetch(url, {
    ...options,
    headers: {
      ...options.headers,
      Authorization: `Bearer ${accessToken}`,
    },
  });

  if (response.status === 401) {
    try {
      const refreshedTokens = await tokenManager.performTokenRefresh();
      return fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${refreshedTokens.accessToken}`,
        },
      });
    } catch (refreshError) {
      throw new Error('Authentication expired. Please log in again.');
    }
  }

  return response;
}

// Main App Component
export default function App() {
  const [authState, setAuthState] = useState({
    isLoading: true,
    isAuthenticated: false,
    tokens: null,
    userInfo: null,
    error: null,
  });

  const discovery = {
    authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
    tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
    revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
  };

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
      extraParams: {
        access_type: 'offline',
        prompt: 'consent',
      },
    },
    discovery
  );

  // Set up token manager callbacks
  useEffect(() => {
    tokenManager.setCallbacks(
      (tokens) => {
        setAuthState((prev) => ({
          ...prev,
          tokens,
          isAuthenticated: true,
        }));
      },
      (error) => {
        console.error('Auth error, logging out:', error);
        handleLogout();
      }
    );

    return () => {
      tokenManager.cancelScheduledRefresh();
    };
  }, []);

  // Check for existing session on app start
  useEffect(() => {
    checkExistingSession();
  }, []);

  // Handle authorization response
  useEffect(() => {
    if (response?.type === 'success') {
      handleAuthorizationResponse(response);
    } else if (response?.type === 'error') {
      setAuthState((prev) => ({
        ...prev,
        isLoading: false,
        error: response.error?.message || 'Authorization failed',
      }));
    }
  }, [response]);

  const checkExistingSession = async () => {
    try {
      const tokens = await tokenManager.getStoredTokens();

      if (tokens) {
        if (tokenManager.isTokenExpired(tokens.expiryTime)) {
          if (tokens.refreshToken) {
            try {
              const refreshedTokens = await tokenManager.performTokenRefresh();
              const userInfo = await fetchUserInfo(refreshedTokens.accessToken);
              setAuthState({
                isLoading: false,
                isAuthenticated: true,
                tokens: refreshedTokens,
                userInfo,
                error: null,
              });
              return;
            } catch (refreshError) {
              console.error('Failed to refresh token on startup:', refreshError);
              await tokenManager.clearTokens();
            }
          } else {
            await tokenManager.clearTokens();
          }
        } else {
          // Token is still valid
          const remainingSeconds = Math.floor(
            (tokens.expiryTime - Date.now()) / 1000
          );
          tokenManager.scheduleTokenRefresh(remainingSeconds);

          const userInfo = await fetchUserInfo(tokens.accessToken);
          setAuthState({
            isLoading: false,
            isAuthenticated: true,
            tokens,
            userInfo,
            error: null,
          });
          return;
        }
      }

      setAuthState({
        isLoading: false,
        isAuthenticated: false,
        tokens: null,
        userInfo: null,
        error: null,
      });
    } catch (error) {
      console.error('Session check error:', error);
      setAuthState({
        isLoading: false,
        isAuthenticated: false,
        tokens: null,
        userInfo: null,
        error: null,
      });
    }
  };

  const handleAuthorizationResponse = async (authResponse) => {
    try {
      setAuthState((prev) => ({ ...prev, isLoading: true, error: null }));

      const { code } = authResponse.params;

      if (!code) {
        throw new Error('No authorization code received');
      }

      const tokens = await tokenManager.exchangeCodeForTokens(
        code,
        request?.codeVerifier
      );

      const userInfo = await fetchUserInfo(tokens.accessToken);

      setAuthState({
        isLoading: false,
        isAuthenticated: true,
        tokens,
        userInfo,
        error: null,
      });
    } catch (error) {
      console.error('Token exchange error:', error);
      setAuthState({
        isLoading: false,
        isAuthenticated: false,
        tokens: null,
        userInfo: null,
        error: error.message,
      });
    }
  };

  const fetchUserInfo = async (accessToken) => {
    try {
      const response = await fetch(OAUTH_CONFIG.userInfoEndpoint, {
        headers: {
          Authorization: `Bearer ${accessToken}`,
        },
      });

      if (response.ok) {
        return await response.json();
      }
      return null;
    } catch (error) {
      console.error('Failed to fetch user info:', error);
      return null;
    }
  };

  const handleLogin = async () => {
    try {
      setAuthState((prev) => ({ ...prev, isLoading: true, error: null }));
      await promptAsync();
    } catch (error) {
      setAuthState((prev) => ({
        ...prev,
        isLoading: false,
        error: error.message,
      }));
    }
  };

  const handleLogout = async () => {
    try {
      setAuthState((prev) => ({ ...prev, isLoading: true }));
      await tokenManager.revokeToken();
      setAuthState({
        isLoading: false,
        isAuthenticated: false,
        tokens: null,
        userInfo: null,
        error: null,
      });
    } catch (error) {
      console.error('Logout error:', error);
      setAuthState({
        isLoading: false,
        isAuthenticated: false,
        tokens: null,
        userInfo: null,
        error: null,
      });
    }
  };

  const handleManualRefresh = async () => {
    try {
      setAuthState((prev) => ({ ...prev, isLoading: true }));
      const tokens = await tokenManager.performTokenRefresh();
      const userInfo = await fetchUserInfo(tokens.accessToken);
      setAuthState((prev) => ({
        ...prev,
        isLoading: false,
        tokens,
        userInfo,
        error: null,
      }));
      Alert.alert('Success', 'Token refreshed successfully');
    } catch (error) {
      Alert.alert('Error', `Token refresh failed: ${error.message}`);
      setAuthState((prev) => ({ ...prev, isLoading: false }));
    }
  };

  const handleTestApiCall = async () => {
    try {
      const response = await authenticatedFetch(
        'https://your-api-server.com/api/protected-resource'
      );
      const data = await response.json();
      Alert.alert('API Response', JSON.stringify(data, null, 2));
    } catch (error) {
      Alert.alert('API Error', error.message);
    }
  };

  if (authState.isLoading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#007AFF" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  if (!authState.isAuthenticated) {
    return (
      <View style={styles.container}>
        <View style={styles.loginContainer}>
          <Text style={styles.title}>OAuth 2.0 Demo</Text>
          <Text style={styles.subtitle}>Cross-Platform Mobile App</Text>

          <View style={styles.warningBox}>
            <Text style={styles.warningTitle}>⚠️ Security Notice</Text>
            <Text style={styles.warningText}>
              This app includes client_secret in the configuration for
              demonstration purposes. In production, mobile apps should use PKCE
              without client_secret or route token exchange through a secure
              backend.
            </Text>
          </View>

          {authState.error && (
            <View style={styles.errorBox}>
              <Text style={styles.errorText}>{authState.error}</Text>
            </View>
          )}

          <TouchableOpacity
            style={[styles.button, styles.loginButton]}
            onPress={handleLogin}
            disabled={!request}
          >
            <Text style={styles.buttonText}>Sign In with OAuth</Text>
          </TouchableOpacity>

          <Text style={styles.redirectText}>
            Redirect URI: {OAUTH_CONFIG.redirectUri}
          </Text>
        </View>
      </View>
    );
  }

  return (
    <ScrollView style={styles.scrollContainer}>
      <View style={styles.authenticatedContainer}>
        <Text style={styles.title}>Welcome!</Text>

        {authState.userInfo && (
          <View style={styles.userInfoCard}>
            <Text style={styles.cardTitle}>User Information</Text>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Name:</Text>
              <Text style={styles.infoValue}>
                {authState.userInfo.name || 'N/A'}
              </Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Email:</Text>
              <Text style={styles.infoValue}>
                {authState.userInfo.email || 'N/A'}
              </Text>
            </View>
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Subject:</Text>
              <Text style={styles.infoValue}>
                {authState.userInfo.sub || 'N/A'}
              </Text>
            </View>
          </View>
        )}

        <View style={styles.tokenInfoCard}>
          <Text style={styles.cardTitle}>Token Information</Text>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Access Token:</Text>
            <Text style={styles.infoValue} numberOfLines={1}>
              {authState.tokens?.accessToken
                ? `${authState.tokens.accessToken.substring(0, 20)}...`
                : 'N/A'}
            </Text>
          </View>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Refresh Token:</Text>
            <Text style={styles.infoValue} numberOfLines={1}>
              {authState.tokens?.refreshToken
                ? `${authState.tokens.refreshToken.substring(0, 20)}...`
                : 'N/A'}
            </Text>
          </View>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Expires:</Text>
            <Text style={styles.infoValue}>
              {authState.tokens?.expiryTime
                ? new Date(authState.tokens.expiryTime).toLocaleString()
                : 'N/A'}
            </Text>
          </View>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Status:</Text>
            <Text
              style={[
                styles.infoValue,
                {
                  color:
                    authState.tokens?.expiryTime &&
                    !tokenManager.isTokenExpired(authState.tokens.expiryTime)
                      ? '#34C759'
                      : '#FF3B30',
                },
              ]}
            >
              {authState.tokens?.expiryTime &&
              !tokenManager.isTokenExpired(authState.tokens.expiryTime)
                ? '● Valid'
                : '● Expired/Expiring Soon'}
            </Text>
          </View>
        </View>

        <View style={styles.actionsContainer}>
          <TouchableOpacity
            style={[styles.button, styles.refreshButton]}
            onPress={handleManualRefresh}
          >
            <Text style={styles.buttonText}>Refresh Token</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.button, styles.apiButton]}
            onPress={handleTestApiCall}
          >
            <Text style={styles.buttonText}>Test API Call</Text>
          </TouchableOpacity>

          <TouchableOpacity
            style={[styles.button, styles.logoutButton]}
            onPress={handleLogout}
          >
            <Text style={styles.buttonText}>Sign Out</Text>
          </TouchableOpacity>
        </View>
      </View>
    </ScrollView>
  );
}

